61: func removePrivateLabels(labels data.Labels) data.Labels {
62: 	result := make(data.Labels)
63: 	for k, v := range labels {
64: 		if !strings.HasPrefix(k, "__") && !strings.HasSuffix(k, "__") {
65: 			result[k] = v
66: 		}
67: 	}
68: 	return result
69: }
