71: // labelFingerprint calculates a stable Prometheus-style signature for a label set.
72: func labelFingerprint(labels data.Labels) string {
73: 	sig := prometheus.LabelsToSignature(labels)
74: 	return fmt.Sprintf("%016x", sig)
